                if (s(i) == '0') currentC0 += 1
                else currentC1 += 1
            }

            if (Math.abs(currentC0 - currentC1) <= requiredDiff) {
                maxLenTwo = L
            }

            // Slide the window
            for (i <- L until n) {
                // Add s[i]
                if (s(i) == '0') currentC0 += 1
                else currentC1 += 1

                // Remove s[i-L]
                val leftChar = s(i - L)
                if (leftChar == '0') currentC0 -= 1
                else currentC1 -= 1

                // Check the new window
                if (Math.abs(currentC0 - currentC1) <= requiredDiff) {
                    maxLenTwo = L
                    break // Since we are checking the maximum possible length L, if one exists, this is the answer.
                }
            }
        }
        maxLen = Math.max(maxLen, maxLenTwo)
    }


    // Final check: If maxLen is still 0, and the string is not trivial (N>0), the empty string is always an option.
    // The initialization maxLen = 0 handles this, as the empty string is balanced (length 0).

    maxLen.toInt.toLong
  }
}
